namespace Dataphyre\Panel;

/**
 * Supplies static stylesheet fragments for generated Panel pages.
 *
 * Each method returns a self-contained CSS fragment with selectors scoped to the
 * Panel renderer's dp-panel class family. The fragments are concatenated by
 * renderer paths rather than loaded through a build step, so callers must treat
 * these strings as trusted runtime assets and apply any HTML escaping at the
 * style-tag insertion boundary.
 */
trait PanelRendererAssetsCoreCss {
	/**
	 * Returns the baseline Panel renderer stylesheet.
	 *
	 * This fragment defines the operator shell, navigation cards, widgets,
	 * toolbars, filters, tables, forms, notices, responsive layout, and
	 * theme-toggle controls. CSS custom properties are used as the theming
	 * boundary; missing variables fall back to built-in Panel colors and spacing.
	 *
	 * The string is emitted from a nowdoc so the runtime has no external build
	 * dependency for the core panel surface.
	 *
	 * @return string Core Panel CSS.
	 */
	private static function css(): string {
		return <<<'CSS'
*{box-sizing:border-box}html{min-height:100%;background:var(--dp-app-bg,#f4f7fb)}body{margin:0;min-height:100%;background:radial-gradient(circle at 18% -8%,rgba(37,99,235,.11),transparent 34rem),linear-gradient(180deg,#f8fbff 0,#f3f6fb 28rem,#eef3f8 100%);color:var(--dp-text,#18202a);font-family:Inter,ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;font-size:14px;line-height:1.45;-webkit-font-smoothing:antialiased}a{color:var(--dp-primary-700,#175cd3)}button,input,select,textarea{font:inherit}.dp-panel{width:min(100%,1440px);margin:0 auto;padding:28px clamp(18px,3vw,42px) 44px}.dp-panel>header{position:relative;margin:0 0 24px;padding:22px 24px;border:1px solid rgba(148,163,184,.28);border-radius:18px;background:rgba(255,255,255,.86);box-shadow:0 18px 50px rgba(15,23,42,.08);backdrop-filter:blur(16px)}header p{margin:0 0 5px;color:var(--dp-text_muted,#667085);font-size:12px;font-weight:750;letter-spacing:.04em;text-transform:uppercase}.dp-panel-heading-row{display:flex;align-items:flex-end;justify-content:space-between;gap:18px}.dp-panel-brand{margin:0 0 12px}.dp-panel-brand img{display:block;max-width:190px}.dp-panel-brand-logo-dark{display:none}.dp-panel-breadcrumbs{display:flex;flex-wrap:wrap;gap:7px;align-items:center;margin:0 0 12px;color:var(--dp-text_soft,#98a2b3);font-size:12px}.dp-panel-breadcrumbs a,.dp-panel-breadcrumbs span{display:inline-flex;align-items:center;min-height:24px;border-radius:999px;text-decoration:none;font-weight:750}.dp-panel-breadcrumbs a{color:var(--dp-primary-700,#175cd3)}.dp-panel-breadcrumbs a:hover{background:rgba(37,99,235,.08);padding-inline:8px;margin-inline:-8px}.dp-panel-breadcrumbs span{color:var(--dp-text_muted,#667085)}.dp-panel-breadcrumbs a:after{content:"/";margin-left:7px;color:var(--dp-text_soft,#98a2b3);font-weight:500}h1{margin:0;color:var(--dp-text,#18202a);font-size:clamp(26px,3vw,38px);line-height:1.06;letter-spacing:0;font-weight:820}h2{margin:24px 0 10px;color:var(--dp-text,#18202a);font-size:18px;line-height:1.2}.dp-panel-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(230px,1fr));gap:14px}.dp-panel-card,.dp-panel-custom-page>section,.dp-panel-custom-page>article{border:1px solid rgba(148,163,184,.28);border-radius:16px;background:rgba(255,255,255,.9);box-shadow:0 14px 38px rgba(15,23,42,.07);padding:18px}.dp-panel-card h2:first-child,.dp-panel-custom-page h2:first-child{margin-top:0}.dp-panel-nav-group{margin:0 0 24px}.dp-panel-nav-group header{display:flex;justify-content:space-between;align-items:center;gap:12px;margin:0 0 11px}.dp-panel-nav-group h2{margin:0;font-size:14px;letter-spacing:.04em;text-transform:uppercase;color:var(--dp-text_muted,#667085)}.dp-panel-nav-group header span{color:var(--dp-text_soft,#98a2b3);font-size:12px;font-weight:750}.dp-panel-nav-card{display:block;min-height:116px;padding:17px;border:1px solid rgba(148,163,184,.30);border-radius:14px;background:rgba(255,255,255,.92);color:var(--dp-text,#18202a);text-decoration:none;box-shadow:0 8px 24px rgba(15,23,42,.045);transition:transform .16s ease,border-color .16s ease,box-shadow .16s ease}.dp-panel-nav-card:hover{transform:translateY(-2px);border-color:rgba(37,99,235,.35);box-shadow:0 16px 40px rgba(15,23,42,.10)}.dp-panel-nav-card span{display:flex;justify-content:space-between;gap:10px;align-items:flex-start;font-size:15px;font-weight:800}.dp-panel-nav-card small{display:block;margin-top:7px;color:var(--dp-text_muted,#667085)}.dp-panel-nav-badge,.dp-panel-badge{display:inline-flex;align-items:center;justify-content:center;gap:5px;min-height:22px;border-radius:999px;background:var(--dp-neutral_bg,#eef2f7);color:var(--dp-neutral_text,#344054);padding:3px 9px;font-size:11px;font-weight:800;line-height:1.2;white-space:nowrap}.dp-panel-nav-badge-primary,.dp-panel-badge-primary{background:var(--dp-primary-50,#e8f1ff);color:var(--dp-primary-700,#175cd3)}.dp-panel-nav-badge-success,.dp-panel-badge-success{background:var(--dp-success-50,#ecfdf3);color:var(--dp-success-700,#067647)}.dp-panel-nav-badge-warning,.dp-panel-badge-warning{background:var(--dp-warning-50,#fffaeb);color:var(--dp-warning-700,#b54708)}.dp-panel-nav-badge-danger,.dp-panel-badge-danger{background:var(--dp-danger-50,#fff1f0);color:var(--dp-danger-700,#b42318)}.dp-panel-nav-badge-info,.dp-panel-badge-info{background:var(--dp-info-50,#eff8ff);color:var(--dp-info-700,#026aa2)}.dp-panel-widgets{display:grid;grid-template-columns:repeat(auto-fit,minmax(210px,1fr));gap:14px;margin:0 0 20px}.dp-panel-widget{display:grid;gap:6px;position:relative;min-height:122px;border:1px solid rgba(148,163,184,.28);border-top:4px solid var(--dp-neutral-400,#98a2b3);border-radius:16px;background:rgba(255,255,255,.92);color:var(--dp-text,#18202a);padding:16px 17px;text-decoration:none;box-shadow:0 12px 30px rgba(15,23,42,.055);overflow:hidden}.dp-panel-widget:before{content:"";position:absolute;inset:auto -26px -38px auto;width:110px;height:110px;border-radius:999px;background:currentColor;opacity:.035}.dp-panel-widget strong{font-size:30px;line-height:1.05;font-weight:850;letter-spacing:0}.dp-panel-widget small{color:var(--dp-text_muted,#667085)}.dp-panel-widget-label{font-size:11px;color:var(--dp-text_muted,#667085);font-weight:820;letter-spacing:.045em;text-transform:uppercase}.dp-panel-widget-icon{position:absolute;right:15px;top:13px;color:var(--dp-text_soft,#98a2b3);font-size:13px;font-weight:800}.dp-panel-widget-primary{border-top-color:var(--dp-primary-600,#1f6feb)}.dp-panel-widget-success{border-top-color:var(--dp-success-600,#079455)}.dp-panel-widget-warning{border-top-color:var(--dp-warning-600,#dc6803)}.dp-panel-widget-danger{border-top-color:var(--dp-danger-600,#d92d20)}.dp-panel-widget-info{border-top-color:var(--dp-info-600,#026aa2)}.dp-panel-toolbar{display:flex;justify-content:space-between;gap:12px;margin:0 0 14px;align-items:flex-start}.dp-panel-toolbar-actions{display:flex;gap:8px;align-items:center;justify-content:flex-end;flex-wrap:wrap}.dp-panel-density{display:inline-flex;border:1px solid rgba(148,163,184,.35);border-radius:999px;overflow:hidden;background:rgba(255,255,255,.85);padding:3px}.dp-panel-density a{min-height:32px;padding:7px 11px;border-radius:999px;color:var(--dp-text_muted,#667085);text-decoration:none;font-size:12px;font-weight:800}.dp-panel-density a.active{background:var(--dp-primary-600,#1f6feb);color:#fff;box-shadow:0 5px 16px rgba(37,99,235,.25)}.dp-panel-column-picker{position:relative}.dp-panel-column-picker summary{border:1px solid rgba(148,163,184,.30);border-radius:999px;background:rgba(255,255,255,.9);color:var(--dp-text,#18202a);padding:8px 13px;font-size:12px;font-weight:800;cursor:pointer;list-style:none;box-shadow:0 5px 14px rgba(15,23,42,.045)}.dp-panel-column-picker summary::-webkit-details-marker{display:none}.dp-panel-column-picker form{position:absolute;right:0;z-index:30;display:grid;gap:9px;min-width:220px;margin-top:8px;border:1px solid rgba(148,163,184,.32);border-radius:14px;background:#fff;padding:12px;box-shadow:0 20px 55px rgba(15,23,42,.18)}.dp-panel-column-picker label{display:flex;gap:8px;align-items:center;white-space:nowrap;color:var(--dp-text,#18202a)}.dp-panel-button,.dp-panel-action{display:inline-flex;align-items:center;justify-content:center;gap:7px;min-height:38px;border:1px solid transparent;border-radius:10px;background:var(--dp-primary-600,#1f6feb);color:#fff;padding:8px 13px;text-decoration:none;font-size:13px;font-weight:820;cursor:pointer;box-shadow:0 7px 18px rgba(37,99,235,.18);transition:transform .12s ease,box-shadow .12s ease,background .12s ease}.dp-panel-button:hover,.dp-panel-action:hover{transform:translateY(-1px);box-shadow:0 12px 24px rgba(15,23,42,.14)}.dp-panel-button-secondary,.dp-panel-action-neutral{border-color:rgba(148,163,184,.28);background:rgba(255,255,255,.9);color:var(--dp-text,#1f2937);box-shadow:0 5px 14px rgba(15,23,42,.045)}.dp-panel-action-primary{background:var(--dp-primary-600,#1f6feb)}.dp-panel-action-success{background:var(--dp-success-600,#079455);box-shadow:0 7px 18px rgba(7,148,85,.18)}.dp-panel-action-warning{background:var(--dp-warning-600,#dc6803);box-shadow:0 7px 18px rgba(220,104,3,.18)}.dp-panel-action-danger{background:var(--dp-danger-600,#d92d20);box-shadow:0 7px 18px rgba(217,45,32,.18)}.dp-panel-inline-action{display:inline}.dp-panel-search,.dp-panel-filters{display:flex;gap:10px;align-items:flex-end;flex-wrap:wrap;margin:0 0 12px}.dp-panel-search input,.dp-panel-filter input,.dp-panel-filter select,.dp-panel-global-search input,.dp-panel-per-page select,.dp-panel-field input,.dp-panel-field select,.dp-panel-field textarea{width:100%;border:1px solid rgba(148,163,184,.42);border-radius:10px;background:rgba(255,255,255,.94);color:var(--dp-text,#18202a);box-shadow:inset 0 1px 0 rgba(15,23,42,.02);outline:none;transition:border-color .12s ease,box-shadow .12s ease,background .12s ease}.dp-panel-search input,.dp-panel-filter input,.dp-panel-filter select,.dp-panel-global-search input,.dp-panel-per-page select{min-height:38px;padding:8px 10px}.dp-panel-field input,.dp-panel-field select,.dp-panel-field textarea{padding:10px 11px;font-size:14px}.dp-panel-search input:focus,.dp-panel-filter input:focus,.dp-panel-filter select:focus,.dp-panel-global-search input:focus,.dp-panel-per-page select:focus,.dp-panel-field input:focus,.dp-panel-field select:focus,.dp-panel-field textarea:focus{border-color:var(--dp-primary-500,#3b82f6);box-shadow:0 0 0 4px rgba(59,130,246,.13);background:#fff}.dp-panel-filter{display:grid;gap:5px;min-width:150px}.dp-panel-filter span{font-size:11px;color:var(--dp-text_muted,#667085);font-weight:820;letter-spacing:.035em;text-transform:uppercase}.dp-panel-range-controls{display:grid;grid-template-columns:repeat(2,minmax(86px,1fr));gap:7px}.dp-panel-table{width:100%;border-collapse:separate;border-spacing:0;background:#fff;border:1px solid rgba(148,163,184,.28);border-radius:14px;box-shadow:0 12px 32px rgba(15,23,42,.055);overflow:hidden}.dp-panel-table th,.dp-panel-table td{padding:12px 14px;border-bottom:1px solid rgba(226,232,240,.9);text-align:left;vertical-align:middle}.dp-panel-table tr:last-child td{border-bottom:0}.dp-panel-table tbody tr{transition:background .12s ease}.dp-panel-table tbody tr:hover{background:#f8fbff}.dp-panel-table-compact th,.dp-panel-table-compact td{padding:8px 10px}.dp-panel-table-comfortable th,.dp-panel-table-comfortable td{padding:16px 18px}.dp-panel-table th{position:relative;background:#f8fafc;color:var(--dp-text_muted,#667085);font-size:11px;font-weight:850;letter-spacing:.045em;text-transform:uppercase}.dp-panel-select{width:38px;text-align:center}.dp-panel-select input{width:16px;height:16px}.dp-panel-sort{color:var(--dp-text_muted,#344054);text-decoration:none}.dp-panel-sort:hover{color:var(--dp-primary-700,#175cd3)}.dp-panel-sort.asc:after{content:" \2191";font-size:11px}.dp-panel-sort.desc:after{content:" \2193";font-size:11px}.dp-panel-cell-link{color:var(--dp-primary-700,#1f6feb);text-decoration:none;font-weight:820}.dp-panel-cell-link:hover{text-decoration:underline}.dp-panel-actions{white-space:nowrap;text-align:right}.dp-panel-actions a,.dp-panel-actions button{margin-left:8px;color:var(--dp-primary-700,#1f6feb);text-decoration:none}.dp-panel-actions button{border:0;background:transparent;padding:0;font:inherit;cursor:pointer}.dp-panel-bulk-form{display:block;overflow-x:auto;padding-bottom:2px}.dp-panel-bulk-bar{display:flex;justify-content:flex-end;gap:8px;margin-top:12px;flex-wrap:wrap}.dp-panel-pagination{display:flex;justify-content:space-between;gap:12px;align-items:center;margin-top:15px;color:var(--dp-text_muted,#667085)}.dp-panel-pagination div{display:flex;gap:8px;align-items:center;flex-wrap:wrap}.dp-panel-page-disabled{display:inline-flex;align-items:center;min-height:38px;border-radius:10px;background:#eef2f7;color:#98a2b3;padding:8px 13px;font-weight:800}.dp-panel-empty{color:var(--dp-text_muted,#667085);padding:18px}.dp-panel-empty-state{display:grid;gap:8px;place-items:center;padding:28px;border:1px dashed rgba(148,163,184,.45);border-radius:14px;background:rgba(255,255,255,.65)}.dp-panel-empty-state span{color:var(--dp-text_muted,#667085)}.dp-panel-form{display:grid;gap:16px;max-width:1040px}.dp-panel-form-section{display:grid;gap:12px;border:1px solid rgba(148,163,184,.24);border-radius:16px;background:rgba(255,255,255,.92);padding:16px;box-shadow:0 10px 28px rgba(15,23,42,.045)}.dp-panel-section-heading{display:grid;gap:4px}.dp-panel-section-heading h2{margin:0;font-size:15px}.dp-panel-section-heading p{margin:0;color:var(--dp-text_muted,#667085)}.dp-panel-form-details{border:1px solid rgba(148,163,184,.28);border-radius:14px;background:rgba(255,255,255,.92);padding:12px 14px}.dp-panel-form-details summary{cursor:pointer;list-style:none;font-weight:820}.dp-panel-form-details summary::-webkit-details-marker{display:none}.dp-panel-form-details[open] summary{margin-bottom:12px}.dp-panel-form-grid{display:grid;gap:14px}.dp-panel-form-grid-2{grid-template-columns:repeat(2,minmax(0,1fr))}.dp-panel-form-grid-3{grid-template-columns:repeat(3,minmax(0,1fr))}.dp-panel-form-grid-4{grid-template-columns:repeat(4,minmax(0,1fr))}.dp-panel-form-grid-5{grid-template-columns:repeat(5,minmax(0,1fr))}.dp-panel-form-grid-6{grid-template-columns:repeat(6,minmax(0,1fr))}.dp-panel-field{display:grid;gap:6px;min-width:0}.dp-panel-field-hidden{display:none}.dp-panel-field-full{grid-column:1/-1}.dp-panel-field-span-2{grid-column:span 2}.dp-panel-field-span-3{grid-column:span 3}.dp-panel-field-span-4{grid-column:span 4}.dp-panel-field-span-5{grid-column:span 5}.dp-panel-field-span-6{grid-column:span 6}.dp-panel-field span{font-size:12px;color:var(--dp-text,#18202a);font-weight:820}.dp-panel-field textarea{min-height:122px;resize:vertical}.dp-panel-field select{height:42px}.dp-panel-field input[type=file]{padding:8px;background:#fff}.dp-panel-field .dp-panel-help{color:var(--dp-text_muted,#667085);font-size:12px}.dp-panel-checkbox{display:flex;align-items:center;gap:8px;font-weight:500}.dp-panel-checkbox input[type=checkbox]{width:18px;height:18px;padding:0;accent-color:var(--dp-primary-600,#1f6feb)}.dp-panel-checkbox span{font-weight:650}.dp-panel-error{color:var(--dp-danger-700,#b42318);font-size:12px;font-weight:750}.dp-panel-alert{border:1px solid #fda29b;background:#fff1f0;color:#912018;border-radius:12px;padding:11px 13px}.dp-panel-relation{margin-top:26px}.dp-panel-notice{display:grid;gap:3px;margin:0 0 12px;border-radius:14px;border:1px solid rgba(148,163,184,.28);background:rgba(255,255,255,.92);padding:12px 14px;box-shadow:0 8px 22px rgba(15,23,42,.04)}.dp-panel-notice span{color:var(--dp-text,#344054)}.dp-panel-notice-success{border-color:#abefc6;background:#ecfdf3}.dp-panel-notice-error{border-color:#fda29b;background:#fff1f0}.dp-panel-notice-warning{border-color:#fedf89;background:#fffaeb}.dp-panel-notice-info{border-color:#b2ddff;background:#eff8ff}.dp-panel-theme-toggle{display:inline-flex;gap:3px;align-items:center;border:1px solid rgba(148,163,184,.30);border-radius:999px;background:rgba(255,255,255,.78);padding:3px}.dp-panel-theme-toggle button{border:0;border-radius:999px;background:transparent;color:var(--dp-text_muted,#667085);padding:7px 10px;font-size:12px;font-weight:800;cursor:pointer}.dp-panel-theme-toggle button[aria-pressed=true]{background:var(--dp-primary-600,#1f6feb);color:#fff;box-shadow:0 5px 16px rgba(37,99,235,.22)}@media(max-width:900px){.dp-panel-toolbar,.dp-panel-heading-row,.dp-panel-pagination{display:grid}.dp-panel-toolbar-actions{justify-content:flex-start}.dp-panel-table{min-width:760px}.dp-panel-bulk-form{margin-inline:-4px;padding-inline:4px}}@media(max-width:760px){.dp-panel{padding:16px 12px 30px}.dp-panel>header{padding:18px;border-radius:15px}.dp-panel-form-grid{grid-template-columns:1fr}.dp-panel-field,.dp-panel-field-full,.dp-panel-field-span-2,.dp-panel-field-span-3,.dp-panel-field-span-4,.dp-panel-field-span-5,.dp-panel-field-span-6{grid-column:1/-1}.dp-panel-search,.dp-panel-filters,.dp-panel-global-search{display:grid}.dp-panel-filter{min-width:0}.dp-panel-theme-toggle{justify-self:start}h1{font-size:28px}}
CSS;
	}

	/**
	 * Returns CSS for resource show, search, table-view, summary, board, and page-table surfaces.
	 *
	 * This fragment extends the core stylesheet with record/table discovery
	 * views and read surfaces that can be emitted by multiple renderer paths. It
	 * assumes css() has already provided the shared button, table, grid, and form
	 * primitives, and does not repeat those defaults.
	 *
	 * @return string Show/resource CSS.
	 */
	private static function showCss(): string {
		return '.dp-panel-filter-chips{display:flex;flex-wrap:wrap;gap:8px;margin:8px 0 12px}.dp-panel-filter-chip{display:inline-flex;align-items:center;gap:6px;border:1px solid #d9e0ea;border-radius:999px;background:#fff;color:#344054;padding:6px 9px;text-decoration:none}.dp-panel-filter-chip span{color:#667085;font-size:11px;font-weight:700;text-transform:uppercase}.dp-panel-filter-chip strong{font-size:12px}.dp-panel-filter-chip small{color:#1f6feb;font-size:11px;font-weight:700}.dp-panel-per-page{display:flex;gap:6px;align-items:center}.dp-panel-per-page label{display:flex;gap:6px;align-items:center;color:#667085;font-size:12px;font-weight:700}.dp-panel-per-page select{border:1px solid #cad3df;border-radius:6px;background:#fff;color:#18202a;padding:8px 9px}.dp-panel-global-search{display:flex;gap:8px;margin:0 0 16px}.dp-panel-global-search input{flex:1;border:1px solid #cad3df;border-radius:6px;padding:10px 12px;font-size:15px;background:#fff;color:#18202a}.dp-panel-search-results{display:grid;gap:8px;margin:0 0 18px}.dp-panel-search-results header{display:flex;justify-content:space-between;align-items:center;margin:0}.dp-panel-search-results h2{margin:0;font-size:16px}.dp-panel-search-results header span{color:#667085;font-size:12px;font-weight:700}.dp-panel-search-result{display:grid;gap:3px;border:1px solid #d9e0ea;border-radius:8px;background:#fff;padding:12px;color:#18202a;text-decoration:none}.dp-panel-search-result span{color:#667085;font-size:12px;font-weight:700;text-transform:uppercase}.dp-panel-search-result strong{font-size:16px}.dp-panel-search-result small{color:#667085}.dp-panel-table-views{display:flex;flex-wrap:wrap;gap:8px;margin:0 0 12px}.dp-panel-table-view{display:inline-flex;align-items:center;gap:7px;border:1px solid #d9e0ea;border-radius:999px;background:#fff;color:#344054;padding:7px 11px;text-decoration:none;font-weight:700}.dp-panel-table-view small{border-radius:999px;background:#eef2f7;color:#344054;padding:2px 7px;font-size:11px}.dp-pane