cf2);border-radius:999px;background:var(--dp-surface,#fff);color:var(--dp-text_muted,#667085);padding:6px 9px;font:inherit;font-size:11px;font-weight:900;line-height:1;cursor:pointer;box-shadow:0 4px 10px rgba(15,23,42,.035);transition:background .14s ease,border-color .14s ease,color .14s ease,transform .14s ease}.dp-panel-entry-copy:hover{transform:translateY(-1px);border-color:var(--dp-primary-600,#2563eb);color:var(--dp-primary-700,#175cd3)}.dp-panel-entry-copy.dp-panel-entry-copy-copied{border-color:color-mix(in srgb,var(--dp-success-600,#16a34a) 40%,var(--dp-border));background:var(--dp-success-50,#ecfdf3);color:var(--dp-success-800,#085d3a)}.dp-panel-entry-description{display:block;color:var(--dp-text_muted,#667085);font-size:12px;font-weight:650;line-height:1.38}.dp-panel-entry-media{display:block;min-width:0}.dp-panel-entry-media img{display:block;width:auto;max-width:100%;max-height:240px;border:1px solid var(--dp-border_soft,#e7ecf2);border-radius:14px;object-fit:cover;background:var(--dp-surface_muted,#f8fafc);box-shadow:0 10px 24px rgba(15,23,42,.06)}.dp-panel-entry-list{display:grid;grid-template-columns:repeat(auto-fit,minmax(130px,1fr));gap:7px;margin:0;padding:0;list-style:none}.dp-panel-entry-list li{min-width:0;border:1px solid var(--dp-border_soft,#e7ecf2);border-radius:12px;background:color-mix(in srgb,var(--dp-surface_muted,#f8fafc) 74%,var(--dp-surface,#fff));color:var(--dp-text,#18202a);padding:8px 10px;font-size:13px;font-weight:760;line-height:1.28;white-space:normal;overflow-wrap:anywhere}.dp-panel-show-field>.dp-panel-badge,.dp-panel-show-field strong>.dp-panel-badge{width:max-content;max-width:100%;white-space:normal}.dp-panel-show-field-copyable{padding-right:12px}.dp-panel-show-field-copyable:after{content:"";position:absolute;inset:0;border-radius:inherit;pointer-events:none;background:linear-gradient(90deg,transparent 70%,color-mix(in srgb,var(--dp-primary-50,#eff6ff) 38%,transparent));opacity:.48}.dp-panel-show .dp-panel-form-sectio