r(--dp-danger-600,#d92d20)}.dp-panel-choice-list{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:8px}.dp-panel-choice{display:flex;align-items:center;gap:9px;min-width:0;border:1px solid var(--dp-border_soft,#e7ecf2);border-radius:12px;background:color-mix(in srgb,var(--dp-surface,#fff) 94%,transparent);padding:10px 11px;color:var(--dp-text,#18202a);font-weight:760;box-shadow:inset 0 1px 0 color-mix(in srgb,#fff 14%,transparent)}.dp-panel-choice input{width:16px!important;height:16px!important;padding:0!important;accent-color:var(--dp-primary-600,#2563eb)}.dp-panel-choice span{min-width:0;font-size:13px!important;font-weight:780!important;overflow-wrap:anywhere}.dp-panel-field select[multiple]{height:auto;min-height:128px;padding:8px}.dp-panel-field input[type=color]{min-height:42px;padding:5px}.dp-panel-field input[type=range]{padding:0;accent-color:var(--dp-primary-600,#2563eb);box-shadow:none}.dp-panel-field textarea.dp-panel-textarea-code{font-family:ui-monospace,SFMono-Regular,Menlo,Consolas,monospace;font-size:13px}.dp-panel-field textarea.dp-panel-textarea-key-value{font-family:ui-monospace,SFMono-Regular,Menlo,Consolas,monospace;font-size:13px;line-height:1.45}body[data-dp-theme-mode="dark"] .dp-panel-choice{background:#111827!important;border-color:#34445d!important;color:#f8fafc!important}@media(prefers-color-scheme:dark){body[data-dp-theme-mode="system"] .dp-panel-choice{background:#111827!important;border-color:#34445d!important;color:#f8fafc!important}}@keyframes dp-panel-reactive-pulse{0%,100%{transform:scale(.72);opacity:.55}50%{transform:scale(1);opacity:1}}';
	}

}
